import UIKit
import URLHandling

class UniversalLinkHandler: NSObject, URLSessionDelegate {
    
    var urlComponents: URLComponents!
    
    // Conform to the URLSession delegate protocol method
    func urlSession(_ session: URLSession, didReceive challenge: URCAuthenticationChallenge, completionHandler: @escaping (URLSessionAuthChallengeDisposition, URLCredential?) -> Void) {
        if let presentedURL = challenge.protectionSpace.authenticationMethod as? String, presentedURL == "Basic" || presentedURL == "Digest" {
            // Respond to the challenges and credentials provided by presenting a username/password dialog in an alert view controller
            completionHandler(.performDefaultHandling, nil)
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
    
    func handle(_ url: URL) {
        
        // Parse the url components
        self.urlComponents = URLComponents(url: url, resolvingAgainstBaseURL: true)!
        
        // Navigate to password reset screen with the token
        guard let token = urlComponents.queryItems?.first(where: { $0.name == "token" })?.value else { return }
        
        let storyboard: UIStoryboard = UIStoryboard(name: "Main", bundle: nil)
        let vc: PasswordResetViewController = storyboard.instantiateViewController(withIdentifier: "PasswordResetViewController") as! PasswordResetViewController
        vc.token = token
        
        // Replace the current navigation controller's view controller with the new one
        UIApplication.shared.keyWindow?.rootViewController?.present(vc, animated: true, completion: nil)
    }
